/**
 * n8n — Strict JSON Validator
 * Hard fail with structured error (WORKING)
 */

function raise(code, message, path) {
  const payload = {
    code,
    message,
    path,
    input
  };

  const err = new Error();
  err.message = JSON.stringify(payload); // 👈 ÚNICA forma que o n8n preserva
  throw err;
}

// ---------- Helpers ----------
function isString(v) {
  return typeof v === "string" && v.trim().length > 0;
}

function match(v, regex) {
  return regex.test(v);
}

// ---------- Input ----------
const input = $input.first().json.body;

// ---------- Root ----------
if (!input || typeof input !== "object" || Array.isArray(input)) {
  raise("INVALID_ROOT", "Input must be a JSON object", "$");
}

// ---------- imagem ----------
if (!isString(input.imagem)) {
  raise("INVALID_FIELD", "imagem is required and must be string", "imagem");
}
if (!match(input.imagem, /^https?:\/\/.+/)) {
  raise("INVALID_FORMAT", "imagem must be a valid URL", "imagem");
}

// ---------- empresa ----------
if (!input.empresa || typeof input.empresa !== "object") {
  raise("INVALID_FIELD", "empresa is required", "empresa");
}

if (!isString(input.empresa.nome)) {
  raise("INVALID_FIELD", "empresa.nome is required", "empresa.nome");
}

if (!match(input.empresa.localidade, /^[A-Za-zÀ-ÿ\s]+\s-\s[A-Z]{2}$/)) {
  raise(
    "INVALID_FORMAT",
    "empresa.localidade must be 'Cidade - UF'",
    "empresa.localidade"
  );
}

// ---------- pessoa ----------
if (!input.pessoa || typeof input.pessoa !== "object") {
  raise("INVALID_FIELD", "pessoa is required", "pessoa");
}

if (!isString(input.pessoa.nome)) {
  raise("INVALID_FIELD", "pessoa.nome is required", "pessoa.nome");
}

if (!match(input.pessoa.telefone, /^\d{10,11}$/)) {
  raise("INVALID_FORMAT", "telefone must have 10 or 11 digits", "pessoa.telefone");
}

if (!match(input.pessoa.cpf, /^\d{3}\.\d{3}\.\d{3}-\d{2}$/)) {
  raise("INVALID_FORMAT", "cpf must be XXX.XXX.XXX-XX", "pessoa.cpf");
}

if (!match(input.pessoa.rg, /^\d{1,2}\.\d{3}\.\d{3}-[\dX]$/)) {
  raise("INVALID_FORMAT", "rg must be XX.XXX.XXX-X", "pessoa.rg");
}

// ---------- Success ----------
return [{ json: input }];
